import React, { useState } from 'react';
import AllProjectData from "./AllProjectData";
import Card from "./Card";
import Categories from "./Categories";
import Certificate from "./Certificate";
import "../node_modules/bootstrap/js/dist/carousel.js";

const allCategories = ["All", ...new Set(AllProjectData.map((item) => item.category))];

const Project = () => {

    const [categories, setCategories] = useState(allCategories);
    const [cardItems, setCardItems] = useState(AllProjectData);

    const menuFilter = (category) => {
        if (category === 'All') {
            return setCardItems(AllProjectData)
        }
        const filteredData = AllProjectData.filter((item) => {
            return item.category === category
        })
        setCardItems(filteredData)
    }

    return (
        < >
            <div>
                <div className="p-2" >
                    <h1 className="text-center">Here Are Some My Project </h1>
                </div>
                <div className="container-fluid">
                    <Categories categories={categories} menuFilter={menuFilter} />
                    <Card cardItems={cardItems} />
                </div>
                <Certificate />
            </div>
        </>
    )
}

export default Project;
