import React from 'react';

const Categories = (props) => {
    return (
        <>
            <div className="nav justify-content-center mb-5 ">
                {
                    props.categories.map((cat, i) => {
                        return (
                            <button type="button" activeClassName="menu_activ" className="btn btn-outline-dark a mx-lg-2 mx-md-1 mx-sm-5 mx-auto my-2"
                                key={i} onClick={() => props.menuFilter(cat)}>{cat}</button>
                        )
                    })
                }
            </div>
        </>
    )
}

export default Categories;
