import React from "react";
import web1 from "../src/images/profile.jpg"
import { NavLink } from "react-router-dom"
import "./index.css"

const Home = () => {
    return (
        <>
            <section className="profile py-lg-3 pt-2 ">
                <div data-aos="fade-up" className="container-fluid nav_bg">
                    <div className="row">
                        <div className="col-10 mx-auto">
                            <div className="row">
                                <div className="col-md-7  pt-lg-0 order-2  order-lg-1 d-flex justify-content-center flex-column ">
                                    <h3 >Hey...! I AM </h3>
                                    <h1 className="display-3" style={{ color: "#242d52" }}>Mayur Gulhane</h1>
                                    <h5 className="my-lg-3">Bachelor of Engineering in Computer Science</h5>
                                    <NavLink exact className="btn btn-danger rounded profile-button mb-lg-0 mb-3" to="/cv">View CV</NavLink>
                                </div>
                                <div className="col-md-5 order-1 order-lg-2 d-flex justify-content-center flex-column pl-lg-5 my-lg-5 my-3 ">
                                    <img src={web1} className="shadow p-1 bg-dark-gray" alt="profile_pic" />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </section>
        </>
    )
}

export default Home
