import React from 'react'
import { NavLink } from "react-router-dom";
import { Twitter, LinkedIn, GitHub, Instagram } from '@material-ui/icons';

const handleURL = (url) => {
  return () => window.open(url, "_blank")
}

const Footer = () => {
  return (
    <>
      <footer className="footer" style={{ backgroundColor: "#1f2235", color: "#fff" }}>
        <div className="container-fluid">
          <h2 className="text-center"> Socialize With Me...!</h2>
          <div className="row text-center  justify-content-center my-lg-3  ">
            <div className="col-2 col-md-1 col-sm-2"
              onClick={handleURL('https://www.linkedin.com/in/mayur-gulhane-1164521a2/')}>
              <LinkedIn fontSize="large" className="icon_1  rounded-circle p-1" />
            </div>
            <div className="col-2 col-md-1 col-sm-2"
              onClick={handleURL('https://github.com/mayurgulhane')}>
              <GitHub fontSize="large" className="icon_2  rounded-circle p-1" />
            </div>
            <div className="col-2 col-md-1 col-sm-2"
              onClick={handleURL('https://www.instagram.com/_mayur_0808/')}>
              <Instagram fontSize="large" className="icon_3   rounded-circle p-1" />
            </div>
            <div className="col-2 col-md-1 col-sm-2"
              onClick={handleURL('https://twitter.com/MayurGulhane7')}>
              <Twitter fontSize="large" className="icon_4 rounded-circle p-1" />
            </div>
          </div>
          <hr />
          <div className="nav align-content-center justify-content-center">
            <NavLink exact className="nav-link " to="/" >HOME</NavLink>
            <NavLink exact className="nav-link" to="/about">ABOUT US</NavLink>
            <NavLink exact className="nav-link" to="/cv">CV</NavLink>
            <NavLink exact className="nav-link" to="/work">WORK</NavLink>
          </div>
        </div>
        <div className="text-center bg-dark p-2" >Copyright &copy; 2021 <strong>Portfolio Website</strong>. | Designed by Mayur</div>
      </footer>
    </>
  )
}
export default Footer