import React from "react";
import web from "../src/images/about.jpg";
import { NavLink } from "react-router-dom";

const About = () => {
  return (
    <>
      <div>
        <h1 className="text-center my-lg-4 my-3"> About Us </h1>
        <div data-aos="zoom-in" className="container d-flex justify-content-center">
          <div className="col-md-6 col-sm-8 mx-auto shadow p-3 mb-5 bg-body rounded">
            <div className="row  g-0">
              <div className="col-auto mx-auto">
                <img className="img-fluid" src={web} alt="profile_img" />
              </div>
              <div className="col p-lg-4 p-4 d-flex flex-column">
                <h2 className="d-inline-block mb-2 text-primary">Hello</h2>
                <p className="card-text mb-auto pb-2" style={{ fontSize: "18px" }}>Welcome to my personal portfolio . My name is Mayur Gulhane ,
                I am from Yavatmal , Maharastra. I have completed my gradution in B.E Computer Science from Sant Gadge
                Baba Amaravati University .
              </p>
                <NavLink exact className="btn btn-danger rounded profile-button" to="/cv">View CV</NavLink>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  )
}
export default About;